let raw = global.get('ZonneplanTijdsloten');
if (!raw || !raw.data || !Array.isArray(raw.data) || raw.data.length < 24) {
    node.status({fill:'red',shape:'ring',text:'no ZonneplanTijdsloten'});
    return null;
}

const cheapCount = 4;
const expensiveMaxCount = 1; // aantal dure uren voor max ontladen
const minSpread = 0.08;   // 8 cent boven gemiddelde goedkope uren

let uren = raw.data.map((item, index) => ({
    uur: index,
    prijs: Number(item.prijsZP)
})).filter(x => !isNaN(x.prijs));

if (uren.length === 0) {
    node.status({fill:'red',shape:'ring',text:'no valid prices'});
    return null;
}

let goedkoopstePrijs = Math.min(...uren.map(x => x.prijs));

let cheapHours = [...uren]
    .sort((a, b) => a.prijs - b.prijs)
    .slice(0, cheapCount)
    .sort((a, b) => a.uur - b.uur)
    .map(x => x.uur);

// Gemiddelde prijs van de gekozen goedkope uren berekenen
let cheapPrices = uren
    .filter(x => cheapHours.includes(x.uur))
    .map(x => x.prijs);

let cheapAvg = cheapPrices.length
    ? cheapPrices.reduce((a, b) => a + b, 0) / cheapPrices.length
    : goedkoopstePrijs;

// Alleen het duurste uur kiezen als het genoeg boven cheapAvg ligt
let expensiveHours = [...uren]
    .filter(x => x.prijs >= (cheapAvg + minSpread))
    .sort((a, b) => b.prijs - a.prijs)
    .slice(0, expensiveMaxCount)
    .sort((a, b) => a.uur - b.uur)
    .map(x => x.uur);

function mergeHoursToSlots(hours) {
    if (!hours.length) return [];
    let slots = [];
    let start = hours[0];
    let end = hours[0];
    for (let i = 1; i < hours.length; i++) {
        if (hours[i] === end + 1) {
            end = hours[i];
        } else {
            slots.push({
                starttijd: start.toString().padStart(2, '0') + ':00',
                eindtijd: (end + 1).toString().padStart(2, '0') + ':00'
            });
            start = hours[i];
            end = hours[i];
        }
    }
    slots.push({
        starttijd: start.toString().padStart(2, '0') + ':00',
        eindtijd: (end + 1).toString().padStart(2, '0') + ':00'
    });
    return slots;
}

let cheapSlots = mergeHoursToSlots(cheapHours);
let expensiveSlots = mergeHoursToSlots(expensiveHours);

global.set('ZonneplanCheapHours', cheapHours);
global.set('ZonneplanCheapSlots', cheapSlots);
global.set('ZonneplanExpensiveHours', expensiveHours);
global.set('ZonneplanExpensiveSlots', expensiveSlots);
global.set('ZonneplanCheapAvg', cheapAvg);

msg.payload = {
    cheapHours,
    cheapSlots,
    expensiveHours,
    expensiveSlots,
    goedkoopstePrijs,
    cheapAvg
};

node.status({
    fill:'green',
    shape:'dot',
    text:'cheap ' + cheapHours.join(',') + ' | exp ' + (expensiveHours.length ? expensiveHours.join(',') : 'none')
});

return msg;

// ===============================
// ETA STATUS AWARE V2
// Uses BatterySOC + TotalBatteryPower + statusBat1/2
// Uses setMax / setMin as targets
// ===============================

const p = msg.payload || {};

// ===============================
// BATTERY CONFIG
// ===============================
const batteryModules = Number(global.get("BatteryModules") || 4);
const batteryModuleCapacityKWh = Number(global.get("BatteryModuleCapacityKWh") || 2.12);
const usableFactor = Number(global.get("BatteryUsableFactor") || 0.90);
const batteryCapacityKWh = batteryModules * batteryModuleCapacityKWh * usableFactor;

// ===============================
// SOC
// ===============================
let socRaw = global.get("BatterySOC");
if (socRaw === undefined || socRaw === null || socRaw === "") socRaw = p.soc;
const soc = Number(socRaw);

// ===============================
// MODE
// ===============================
const mode = p.mode || global.get("EnergyMode") || "SELF";

// ===============================
// BATTERY STATUS
// ===============================
const statusBat1 = String(global.get("statusBat1") || "").toUpperCase();
const statusBat2 = String(global.get("statusBat2") || "").toUpperCase();

function isDischargingStatus(s) {
    return s.includes("DISCHARGE") || s.includes("DISCHARGING");
}

function isChargingStatus(s) {
    return !isDischargingStatus(s) && (s.includes("CHARGE") || s.includes("CHARGING"));
}

const chargingCount =
    (isChargingStatus(statusBat1) ? 1 : 0) +
    (isChargingStatus(statusBat2) ? 1 : 0);

const dischargingCount =
    (isDischargingStatus(statusBat1) ? 1 : 0) +
    (isDischargingStatus(statusBat2) ? 1 : 0);

let etaDirection = "NONE";

if (chargingCount > dischargingCount) {
    etaDirection = "CHARGE";
} else if (dischargingCount > chargingCount) {
    etaDirection = "DISCHARGE";
} else if (mode === "CHARGE" || mode === "DISCHARGE") {
    etaDirection = mode;
}

// ===============================
// POWER
// ===============================
const totalBatteryPowerW = Number(global.get("TotalBatteryPower") || 0);
const fallbackChargePowerW = Number(global.get("ChargePowerW") || 2500);
const fallbackDischargePowerW = Number(global.get("DischargePowerW") || 2500);
const minValidPowerW = Number(global.get("MinValidBatteryPowerW") || 50);

// true  = TotalBatteryPower > 0 means charging
// false = TotalBatteryPower > 0 means discharging
const batteryPowerPositiveIsCharging = true;

let usedPowerW = 0;
let powerSource = "none";

function getChargePower() {
    if (batteryPowerPositiveIsCharging && totalBatteryPowerW > minValidPowerW) {
        powerSource = "live";
        return totalBatteryPowerW;
    }
    if (!batteryPowerPositiveIsCharging && totalBatteryPowerW < -minValidPowerW) {
        powerSource = "live";
        return Math.abs(totalBatteryPowerW);
    }
    powerSource = "fallback";
    return fallbackChargePowerW;
}

function getDischargePower() {
    if (batteryPowerPositiveIsCharging && totalBatteryPowerW < -minValidPowerW) {
        powerSource = "live";
        return Math.abs(totalBatteryPowerW);
    }
    if (!batteryPowerPositiveIsCharging && totalBatteryPowerW > minValidPowerW) {
        powerSource = "live";
        return totalBatteryPowerW;
    }
    powerSource = "fallback";
    return fallbackDischargePowerW;
}

// ===============================
// HELPERS
// ===============================
function calcMinutes(fromSoc, toSoc, powerW) {
    if (isNaN(fromSoc) || isNaN(toSoc)) return null;
    if (!powerW || powerW <= 0) return null;

    const deltaSoc = Math.abs(toSoc - fromSoc);
    if (deltaSoc <= 0) return 0;

    const energyKWh = batteryCapacityKWh * (deltaSoc / 100);
    const powerKW = powerW / 1000;

    return Math.round((energyKWh / powerKW) * 60);
}

function fmtMinutes(min) {
    if (min === null || isNaN(min)) return "-";

    min = Math.max(0, Math.round(min));

    const h = Math.floor(min / 60);
    const m = min % 60;

    return h > 0 ? `${h}h ${m}m` : `${m}m`;
}

function getNumber(...values) {
    for (const v of values) {
        if (v === undefined || v === null || v === "") continue;
        const n = Number(v);
        if (!isNaN(n)) return n;
    }
    return null;
}

// ===============================
// TARGETS + ETA
// ===============================
let targetSoc = null;
let timeRemainingMin = null;
let timeRemainingText = "-";

if (etaDirection === "CHARGE") {
    targetSoc = getNumber(
        global.get("setMax"),
        p.setMax,
        p.socMax,
        global.get("socMax"),
        global.get("SocMax"),
        100
    );

    usedPowerW = getChargePower();
    timeRemainingMin = targetSoc > soc ? calcMinutes(soc, targetSoc, usedPowerW) : 0;
}

else if (etaDirection === "DISCHARGE") {
    targetSoc = getNumber(
        global.get("setMin"),
        p.setMin,
        p.socMin,
        global.get("socMin"),
        global.get("SocMin"),
        10
    );

    usedPowerW = getDischargePower();
    timeRemainingMin = soc > targetSoc ? calcMinutes(soc, targetSoc, usedPowerW) : 0;
}

timeRemainingText = fmtMinutes(timeRemainingMin);

// ===============================
// OUTPUT ONLY ETA FIELDS
// ===============================
msg.payload = {
    etaDirection,
    etaTargetSoc: targetSoc,
    etaMinutes: timeRemainingMin,
    etaText: timeRemainingText,
    etaUsedPowerW: Math.round(usedPowerW),
    etaPowerSource: powerSource,

    soc,
    mode,
    totalBatteryPowerW,
    statusBat1,
    statusBat2,
    chargingCount,
    dischargingCount,

    batteryCapacityKWh,
    batteryModules,
    batteryModuleCapacityKWh,
    usableFactor
};

node.status({
    fill: etaDirection === "CHARGE" ? "green" : etaDirection === "DISCHARGE" ? "red" : "grey",
    shape: "dot",
    text: `${etaDirection} target=${targetSoc ?? "-"} eta=${timeRemainingText} ${Math.round(usedPowerW)}W ${powerSource}`
});

return msg;

// ===============================
// STABLE MODE ENGINE v5.0 (QUARTER HOUR UPDATE)
// ===============================

const now = Date.now();

// Init Engine
const initDone = global.get("ModeEngineInit");

if (!initDone) {
    global.set("PowerMode", 0);
    global.set("DimSignal", 0);
    global.set("EnergyMode", "SELF");
    global.set("LastMode", "SELF");
    global.set("ModeEngineInit", true);
}

// ---------- INPUTS ----------
let prijsData = global.get('ZonneplanTijdsloten');

// Bevatten nu kwartier-indexen (0 t/m 95) vanuit de nieuwe tijdsloten-code
let cheapQuarters = global.get('ZonneplanCheapHours') || []; 
let expensiveQuarters = global.get('ZonneplanExpensiveHours') || [];
let cheapAvg = Number(global.get('ZonneplanCheapAvg') || 0);

cheapQuarters = Array.isArray(cheapQuarters) ? cheapQuarters : [];
expensiveQuarters = Array.isArray(expensiveQuarters) ? expensiveQuarters : [];

let soc = Number(global.get('BatterySOC') || 0);
let pvRaw = Number(global.get('PVSurplusW') || 0);

// --- NIEUW: Bereken huidige kwartier-index van de dag (0 t/m 95) ---
let dateNow = new Date();
let currentHour = dateNow.getHours();
let currentMinute = dateNow.getMinutes();
let quarterIndex = (currentHour * 4) + Math.floor(currentMinute / 15);
let tijdString = currentHour.toString().padStart(2, '0') + ':' + currentMinute.toString().padStart(2, '0');

// ---------- PRICE CHECK ----------
if (!prijsData?.data?.[quarterIndex]) {
    node.status({ fill: 'red', shape: 'ring', text: 'missing price data for current quarter' });
    return null;
}

let priceNow = Number(prijsData.data[quarterIndex].prijsZP);

// ---------- SETTINGS ----------
const socMin = Number(global.get("setMin") || 30);
const socMax = Number(global.get("setMax") || 90);

const socMinExit = socMin + 3;
const socMaxExit = socMax - 3;

const pvMin = 500;
const dimThreshold = -0.01;
const minSpread = 0.08;
let pvDischargeLimit = Math.max(
    200,
    Math.min(1000, priceNow * 2500)
);


// ---------- LOCK / COOLDOWN ----------
const lastSwitchTs = global.get("LastSwitchTs") || 0;
const lockMs = 2 * 60 * 1000; // 2 min lock

const locked = (now - lastSwitchTs) < lockMs;

// ---------- PV SMOOTHING ----------
let pvFiltered = global.get("PVFiltered") || pvRaw;
pvFiltered = (pvFiltered * 0.7) + (pvRaw * 0.3);
global.set("PVFiltered", pvFiltered);

// ---------- CURRENT STATE ----------
let lastMode = global.get("LastMode") || "SELF";

// ---------- OUTPUT STATE ----------
let powerMode = 0; // 0 SELF or manual, 1 CHARGE or 3, 2 DISCHARGE
let dim = 0;
let mode = "SELF";

// ===============================
// LOCKED STATE (HOLD MODE)
// ===============================
if (locked) {

    node.status({
        fill: "blue",
        shape: "dot",
        text: "LOCKED " + Math.round((lockMs - (now - lastSwitchTs)) / 1000) + "s"
    });

    return [
        { payload: global.get("PowerMode") || 0, topic: "powerMode" },
        { payload: global.get("DimSignal") || 0, topic: "dim" },
        { payload: global.get("EnergyModePayload") || {}, topic: "mode" }
    ];
}

// ===============================
// DIM SIGNAL (non-blocking)
// ===============================
if (
    soc >= socMax &&
    pvFiltered >= pvMin &&
    priceNow <= dimThreshold
) {
    dim = 1;
}


// ===============================
// CHARGE (hysterese)
// ===============================
// Controleert nu of de huidige kwartier-index in de goedkope lijst staat
if (
    cheapQuarters.includes(quarterIndex) &&
    soc < socMaxExit
) {
    powerMode = 3; // grid-charging mode
    mode = "CHARGE";
}

// ===============================
// DISCHARGE (stable entry/exit)
// ===============================
// Controleert nu of de huidige kwartier-index in de dure lijst staat
else if (
    expensiveQuarters.includes(quarterIndex) &&
    soc > socMinExit &&
    priceNow >= (cheapAvg + minSpread)
) {
    powerMode = 2;
    mode = "DISCHARGE";
}

// ===============================
// DEFAULT
// ===============================
else {
    powerMode = 0 ;
    mode = "SELF";
}

// ===============================
// STATE PERSISTENCE
// ===============================
global.set("PowerMode", powerMode);
global.set("DimSignal", dim);
global.set("EnergyMode", mode);

// save payload for reuse in lock
let modePayload = {
    mode,
    powerMode,
    dim,
    hour: currentHour, // behouden voor achterwaartse compatibiliteit dashboard
    quarterIndex,
    time: tijdString,
    priceNow,
    soc,
    pvSurplus: pvFiltered,
    cheapAvg,
    cheapQuarters,
    expensiveQuarters
};

global.set("EnergyModePayload", modePayload);

// ===============================
// SWITCH DETECTION
// ===============================
if (mode !== lastMode) {
    global.set("LastSwitchTs", now);
    node.status({ fill: "blue", shape: "dot", text: "SWITCH " + lastMode + "→" + mode });
}

global.set("LastMode", mode);

// ===============================
// STATUS
// ===============================
node.status({
    fill:
        mode === "CHARGE" ? "green" :
        mode === "DISCHARGE" ? "yellow" :
        mode === "DIM" ? "red" :
        "grey",

    shape: "dot",
    text: `${mode} t=${tijdString} p=${priceNow.toFixed(3)} soc=${soc} pv=${Math.round(pvFiltered)}`
});

// DEBUG
node.warn({
    mode,
    tijd: tijdString,
    quarterIndex,
    priceNow,
    soc,
    pvFiltered,
    pvDischargeLimit
});

// ===============================
// OUTPUTS
// ===============================
return [
    { payload: powerMode, topic: "powerMode" },
    { payload: dim, topic: "dim" },
    { payload: modePayload, topic: "mode" }
];

let raw = global.get('ZonneplanTijdsloten');
if (!raw || !raw.data || !Array.isArray(raw.data) || raw.data.length < 24) {
    node.status({fill:'red',shape:'ring',text:'no ZonneplanTijdsloten'});
    return null;
}

const cheapCount = 4;
const expensiveMaxCount = 1; // aantal dure uren voor max ontladen
const minSpread = 0.08;      // 8 cent boven gemiddelde goedkope uren

let uren = raw.data.map((item, index) => ({
    uur: index,
    prijs: Number(item.prijsZP)
})).filter(x => !isNaN(x.prijs));

if (uren.length === 0) {
    node.status({fill:'red',shape:'ring',text:'no valid prices'});
    return null;
}

let goedkoopstePrijs = Math.min(...uren.map(x => x.prijs));

let cheapHours = [...uren]
    .sort((a, b) => a.prijs - b.prijs)
    .slice(0, cheapCount)
    .sort((a, b) => a.uur - b.uur)
    .map(x => x.uur);

// Gemiddelde prijs van de gekozen goedkope uren berekenen
let cheapPrices = uren
    .filter(x => cheapHours.includes(x.uur))
    .map(x => x.prijs);

let cheapAvg = cheapPrices.length
    ? cheapPrices.reduce((a, b) => a + b, 0) / cheapPrices.length
    : goedkoopstePrijs;

// Duurste uur berekenen
let duurste = [...uren].sort((a, b) => b.prijs - a.prijs)[0];

let duursteUur = duurste.uur;
let duurstePrijs = duurste.prijs;
let spreadDuursteVsCheapAvg = duurstePrijs - cheapAvg;
let spreadDuursteVsGoedkoopste = duurstePrijs - goedkoopstePrijs;
let dischargeAllowed = spreadDuursteVsCheapAvg >= minSpread;

// Alleen het duurste uur kiezen als het genoeg boven cheapAvg ligt
let expensiveHours = [...uren]
    .filter(x => x.prijs >= (cheapAvg + minSpread))
    .sort((a, b) => b.prijs - a.prijs)
    .slice(0, expensiveMaxCount)
    .sort((a, b) => a.uur - b.uur)
    .map(x => x.uur);

function mergeHoursToSlots(hours) {
    if (!hours.length) return [];
    let slots = [];
    let start = hours[0];
    let end = hours[0];

    for (let i = 1; i < hours.length; i++) {
        if (hours[i] === end + 1) {
            end = hours[i];
        } else {
            slots.push({
                starttijd: start.toString().padStart(2, '0') + ':00',
                eindtijd: (end + 1).toString().padStart(2, '0') + ':00'
            });
            start = hours[i];
            end = hours[i];
        }
    }

    slots.push({
        starttijd: start.toString().padStart(2, '0') + ':00',
        eindtijd: (end + 1).toString().padStart(2, '0') + ':00'
    });

    return slots;
}

let cheapSlots = mergeHoursToSlots(cheapHours);
let expensiveSlots = mergeHoursToSlots(expensiveHours);

global.set('ZonneplanCheapHours', cheapHours);
global.set('ZonneplanCheapSlots', cheapSlots);
global.set('ZonneplanExpensiveHours', expensiveHours);
global.set('ZonneplanExpensiveSlots', expensiveSlots);
global.set('ZonneplanCheapAvg', cheapAvg);

global.set('ZonneplanDuursteUur', duursteUur);
global.set('ZonneplanDuurstePrijs', duurstePrijs);
global.set('ZonneplanSpreadDuursteVsCheapAvg', spreadDuursteVsCheapAvg);
global.set('ZonneplanDischargeAllowed', dischargeAllowed);

msg.payload = {
    cheapHours,
    cheapSlots,
    expensiveHours,
    expensiveSlots,
    goedkoopstePrijs,
    cheapAvg,
    duursteUur,
    duurstePrijs,
    spreadDuursteVsCheapAvg,
    spreadDuursteVsGoedkoopste,
    dischargeAllowed
};

node.status({
    fill: dischargeAllowed ? 'green' : 'yellow',
    shape: 'dot',
    text:
        'cheap ' + cheapHours.join(',') +
        ' | duurste ' + duursteUur +
        ' €' + duurstePrijs.toFixed(3) +
        ' spread ' + spreadDuursteVsCheapAvg.toFixed(3)
});

return msg;

// ===============================
// STABLE MODE ENGINE v4 
// ===============================

const now = Date.now();

// Init Engine
const initDone = global.get("ModeEngineInit");

if (!initDone) {
    global.set("PowerMode", 0);
    global.set("DimSignal", 0);
    global.set("EnergyMode", "SELF");
    global.set("LastMode", "SELF");
    global.set("ModeEngineInit", true);
}

// ---------- INPUTS ----------
let prijsData = global.get('ZonneplanTijdsloten');

let cheapHours = global.get('ZonneplanCheapHours') || [];
let expensiveHours = global.get('ZonneplanExpensiveHours') || [];
let cheapAvg = Number(global.get('ZonneplanCheapAvg') || 0);

cheapHours = Array.isArray(cheapHours) ? cheapHours : [];
expensiveHours = Array.isArray(expensiveHours) ? expensiveHours : [];

let soc = Number(global.get('BatterySOC') || 0);
let pvRaw = Number(global.get('PVSurplusW') || 0);

let hour = new Date().getHours();

// ---------- PRICE CHECK ----------
if (!prijsData?.data?.[hour]) {
    node.status({ fill: 'red', shape: 'ring', text: 'missing price data' });
    return null;
}

let priceNow = Number(prijsData.data[hour].prijsZP);

// ---------- SETTINGS ----------
const socMin = Number(global.get("setMin") || 30);
const socMax = Number(global.get("setMax") || 90);

const socMinExit = socMin + 3;
const socMaxExit = socMax - 3;

const pvMin = 500;
const dimThreshold = -0.01;
const minSpread = 0.08;
let pvDischargeLimit = Math.max(
    200,
    Math.min(1000, priceNow * 2500)
);


// ---------- LOCK / COOLDOWN ----------
const lastSwitchTs = global.get("LastSwitchTs") || 0;
const lockMs = 2 * 60 * 1000; // 2 min lock

const locked = (now - lastSwitchTs) < lockMs;

// ---------- PV SMOOTHING ----------
let pvFiltered = global.get("PVFiltered") || pvRaw;
pvFiltered = (pvFiltered * 0.7) + (pvRaw * 0.3);
global.set("PVFiltered", pvFiltered);

// ---------- CURRENT STATE ----------
let lastMode = global.get("LastMode") || "SELF";

// ---------- OUTPUT STATE ----------
let powerMode = 0; // 0 SELF or manual, 1 CHARGE or 3, 2 DISCHARGE
let dim = 0;
let mode = "SELF";

// ===============================
// LOCKED STATE (HOLD MODE)
// ===============================
if (locked) {

    node.status({
        fill: "blue",
        shape: "dot",
        text: "LOCKED " + Math.round((lockMs - (now - lastSwitchTs)) / 1000) + "s"
    });

    return [
        { payload: global.get("PowerMode") || 0, topic: "powerMode" },
        { payload: global.get("DimSignal") || 0, topic: "dim" },
        { payload: global.get("EnergyModePayload") || {}, topic: "mode" }
    ];
}

// ===============================
// DIM SIGNAL (non-blocking)
// ===============================
if (
    soc >= socMax &&
    pvFiltered >= pvMin &&
    priceNow <= dimThreshold
) {
    dim = 1;
}


// ===============================
// CHARGE (hysterese)
// ===============================
if (
    cheapHours.includes(hour) &&
    soc < socMaxExit
) {
    powerMode = 3;// choose self mode 1, or via grid 3 (scheme code 0tm3)
    mode = "CHARGE";
}

// ===============================
// DISCHARGE (stable entry/exit)
// ===============================
else if (
    expensiveHours.includes(hour) &&
    soc > socMinExit &&
    priceNow >= (cheapAvg + minSpread)
) {
    powerMode = 2;
    mode = "DISCHARGE";
}

// ===============================
// DEFAULT
// ===============================
else {
    powerMode = 0 ;// enable for real manual mode, but now only dis/charge mode
    mode = "SELF";// self mode for soft limits path
}

// ===============================
// STATE PERSISTENCE
// ===============================
global.set("PowerMode", powerMode);
global.set("DimSignal", dim);
global.set("EnergyMode", mode);

// save payload for reuse in lock
let modePayload = {
    mode,
    powerMode,
    dim,
    hour,
    priceNow,
    soc,
    pvSurplus: pvFiltered,
    cheapAvg,
    cheapHours,
    expensiveHours
};

global.set("EnergyModePayload", modePayload);

// ===============================
// SWITCH DETECTION
// ===============================
if (mode !== lastMode) {
    global.set("LastSwitchTs", now);
    node.status({ fill: "blue", shape: "dot", text: "SWITCH " + lastMode + "→" + mode });
}

global.set("LastMode", mode);

// ===============================
// STATUS
// ===============================
node.status({
    fill:
        mode === "CHARGE" ? "green" :
        mode === "DISCHARGE" ? "yellow" :
        mode === "DIM" ? "red" :
        "grey",

    shape: "dot",
    text: `${mode} h=${hour} p=${priceNow} soc=${soc} pv=${Math.round(pvFiltered)} lim=${pvDischargeLimit}`
});

// DEBUG
node.warn({
    mode,
    hour,
    priceNow,
    soc,
    pvFiltered,
    pvDischargeLimit
});

// ===============================
// OUTPUTS
// ===============================
return [
    { payload: powerMode, topic: "powerMode" },
    { payload: dim, topic: "dim" },
    { payload: modePayload, topic: "mode" }
];

let raw = global.get('ZonneplanTijdsloten');
