// Charge only trigger - hybrid
// 1 = laden toestaan
// 0 = stoppen/manual om ontladen te voorkomen

const solarstart = 300;
const margin = 50; // W hysteresis / veiligheidsmarge

const solpwr = Number(global.get("SolarPwr") ?? 0);
const use = Number(global.get("ActualUse") ?? 400);

const soc1 = Number(global.get("SocBat1")?.[0]);
const soc2 = Number(global.get("SocBat2")?.[0]);
const soc3 = Number(global.get("SocBat3")?.[0]);

const max = Number(global.get("setMax"));

if ([solpwr, use, soc1, soc2, max].some(v => Number.isNaN(v))) {
    node.status({
        fill: "red",
        shape: "ring",
        text: `missing B1=${soc1} B2=${soc2}`
    });
    return null;
}

// stoppen als alle vol zijn
if (soc1 >= max && soc2 >= max && soc3 >= max) {
    msg.payload = 0;
    msg.topic = "charge-stop-full";

    node.status({
        fill: "blue",
        shape: "dot",
        text: `all full B1=${soc1}% B2=${soc2}% B3=${soc3}% -> 0`
    });

    return msg;
}

// bereken overschot
const surplus = solpwr - use;

// hybride startvoorwaarde
