// ===== BATTERY SELECT =====
const bat = msg.battery || 1;

// ===== INPUT =====
let soc = msg.payload;
//let soc = Number(global.get(`SocBat${bat}`)?.[0]);


// ===== SETTINGS =====
const capacity = 4.2;
const chargeEfficiency = 0.94;
const dischargeEfficiency = 0.94;

// ===== TARGETS =====
let setMin = (global.get("setMin") || 0) * capacity / 100;
let setMax = (global.get("setMax") || 100) * capacity / 100;

// ===== POWER =====
let power = global.get(`Bat${bat}Power`) || 0;

// clamp
if (power > 1500) power = 1500;
if (power < -1500) power = -1500;

// smoothing per batterij
let prev = context.get(`avgPower_${bat}`) || power;
let avgPower = (prev * 0.6) + (power * 0.4);
context.set(`avgPower_${bat}`, avgPower);

power = avgPower;

// noise filter
if (Math.abs(power) < 80) power = 0;

let powerKw = Math.abs(power) / 1000;

// ===== HELPERS =====
function format(hours) {
    if (!isFinite(hours) || hours <= 0) return null;

    let min = Math.round(hours * 60);
    let hh = Math.floor(min / 60);
    let mm = min % 60;

    return `${String(hh).padStart(2,"0")}:${String(mm).padStart(2,"0")}`;
}

function eta(hours) {
    if (!isFinite(hours) || hours <= 0) return "--:--";

    return new Date(Date.now() + hours * 3600000)
        .toLocaleTimeString("nl-NL", {
            hour: "2-digit",
            minute: "2-digit"
        });
}

// ===== OUTPUT VARS =====
let remainingTime = "--:--";
let etaTime = "--:--";
let state = "idle";

// ===== CHARGING =====
if (power > 0 && powerKw > 0 && soc < setMax) {

    state = "charging";

    let hours = (setMax - soc) / (powerKw * chargeEfficiency);

    remainingTime = format(hours) || "--:--";
    etaTime = eta(hours);
}

// ===== DISCHARGING =====
if (power < 0 && powerKw > 0 && soc > setMin) {

    state = "discharging";

    let hours = (soc - setMin) / (powerKw * dischargeEfficiency);

    remainingTime = format(hours) || "--:--";
    etaTime = eta(hours);
}

// ===== STATUS =====
node.status({
    fill: state === "charging" ? "green" :
          state === "discharging" ? "orange" : "grey",
    shape: "dot",
    text: `${state} ${remainingTime} ${etaTime}`
});

// ===== MULTI OUTPUT =====
return [
    { payload: remainingTime },  // OUTPUT 1: time
    { payload: etaTime },        // OUTPUT 2: ETA
    { payload: state }           // OUTPUT 3: state
];

