var wakeUpDone = context.get("wakeUpDone") || false;

var modusWaarde = 64036;
var enablebit = 0;
var statusText = "Manual disabled";

// 3. Modus logica bepalen
if (inputMode === 1) {
    modusWaarde = 65535;
    enablebit = 1;
    statusText = "AntiFeed enabled";
}
else if (inputMode === 2) {
    modusWaarde = vermogen;
    enablebit = 1;
    statusText = "Discharge enabled";
}
else if (inputMode === 3) {
    modusWaarde = (65536 - vermogen);
    enablebit = 1;
    statusText = "Charge enabled";
}

// 4. Reset de wakeUpDone vlag als de zon weer krachtig schijnt
if (pvVermogen >= 300) {
    context.set("wakeUpDone", false);
    wakeUpDone = false;
}

var commands = [];

// 5. CONTROLEER OP WAKE LOOP TRIGGER (Avondval in modus 1)
if (inputMode === 1 && pvVermogen < 300 && !wakeUpDone) {

    statusText = "Wake loop active - Executing Kick...";
    context.set("wakeUpDone", true); // Blokkeer direct volgende herhalingen

    // Volledige herstart-reeks met disable (0) vooraan en enable (1) achteraan
    commands = [
        { value: 0,           fc: 6, unitid: 1, address: 43104, quantity: 1 }, 
        { value: 127,         fc: 6, unitid: 1, address: 43100, quantity: 1 }, 
        { value: 0,           fc: 6, unitid: 1, address: 43101, quantity: 1 },
        { value: 2359,        fc: 6, unitid: 1, address: 43102, quantity: 1 },
        { value: modusWaarde, fc: 6, unitid: 1, address: 43103, quantity: 1 },
        { value: 1,           fc: 6, unitid: 1, address: 43104, quantity: 1 }  
    ];

} else if (msg.payload !== undefined && typeof msg.payload === "number") {
    // HANDMATIGE MODUS-WISSEL (Er komt een echt getal binnen via de knop)
    // Nu OOK hier altijd eerst een disable (0) en aan het einde de gekozen enablebit (0 of 1)
    commands = [
        { value: 0,           fc: 6, unitid: 1, address: 43104, quantity: 1 }, // Schakel eerst uit
        { value: 127,         fc: 6, unitid: 1, address: 43100, quantity: 1 },
        { value: 0,           fc: 6, unitid: 1, address: 43101, quantity: 1 },
        { value: 2359,        fc: 6, unitid: 1, address: 43102, quantity: 1 },
        { value: modusWaarde, fc: 6, unitid: 1, address: 43103, quantity: 1 },
        { value: enablebit,   fc: 6, unitid: 1, address: 43104, quantity: 1 }  // Zet aan in de gekozen modus
    ];
} 

// 6. Verstuur de commando's (alleen als de array gevuld is)
if (commands.length > 0) {
    let timers = context.get("timers") || [];
    timers.forEach(clearTimeout);
    timers = [];

    commands.forEach(function(cmd, index) {
        let t = setTimeout(function() {
            node.send({ payload: cmd });
        }, index * 450);
        timers.push(t);
    });
    context.set("timers", timers);
}

// 7. Update de Node Status live bij elke trigger
node.status({
    fill: enablebit ? "green" : "gray",
    shape: (inputMode === 1 && pvVermogen < 300 && !wakeUpDone) ? "ring" : "dot",
    text: statusText + " (" + modusWaarde + ") | PV: " + pvVermogen + "W"
});

return null;
